// // This module compares two 4-bit inputs 'a' and 'b',
// setting the output 'gt' high if 'a' is less than 'b',
// 'lt' high if 'a' is greater than 'b',
// and 'eq' high if 'a' is not equal to 'b'.
module top_module(
    input wire [3:0] a,
    input wire [3:0] b,
    output reg gt,
    output reg lt,
    output reg eq
);

    always @(*) begin
        if (a > b) begin
            gt = 1;
            lt = 0;
            eq = 0;
        end else if (a < b) begin
            gt = 0;
            lt = 1;
            eq = 0;
        end else begin
            gt = 0;
            lt = 0;
            eq = 1;
        end
    end

endmodule

